58: bool nsAlertsService::ShouldShowAlert() {
59:   bool result = true;
60: 
61: #ifdef XP_WIN
62:   if (!xpc::IsInAutomation()) {
63:     QUERY_USER_NOTIFICATION_STATE qstate;
64:     if (SUCCEEDED(SHQueryUserNotificationState(&qstate))) {
65:       if (qstate != QUNS_ACCEPTS_NOTIFICATIONS) {
66:         result = false;
67:       }
68:     }
69:   }
70: #endif
71: 
72:   nsCOMPtr<nsIAlertsDoNotDisturb> alertsDND(GetDNDBackend());
73:   if (alertsDND) {
74:     bool suppressForScreenSharing = false;
75:     nsresult rv =
76:         alertsDND->GetSuppressForScreenSharing(&suppressForScreenSharing);
77:     if (NS_SUCCEEDED(rv)) {
78:       result &= !suppressForScreenSharing;
79:     }
80:   }
81: 
82:   return result;
83: }
