126:     NS_ENSURE_TRUE(xulBackend, NS_ERROR_FAILURE);
127:     return xulBackend->CloseAlert(aAlertName, aContextClosed);
128:   }
129:   if (!mBackend) {
130:     return NS_ERROR_NOT_AVAILABLE;
131:   }
